int getC(int x) {
    return x * (x - 1) / 2;
}

struct DSU {
    vector<int> p;
    vector<int> size;
    int sum = 0;

    DSU(int n) {
        p.resize(n + 1);
        size.resize(n + 1, 1);
        for (int i = 1; i <= n; i++) {
            p[i] = i;
        }
    }

    int get(int x) {
        return p[x] = x == p[x] ? p[x] : get(p[x]);
    }

    void Union(int x, int y) {
        x = get(x);
        y = get(y);
        sum -= getC(size[x]);
        sum -= getC(size[y]);
        if (size[x] > size[y]) {
            p[y] = x;
            size[x] += size[y];
            size[y] = 0;
            sum += getC(size[x]);
        } else {
            p[x] = y;
            size[y] += size[x];
            size[x] = 0;
            sum += getC(size[y]);
        }
    }
};

