const int N = 500002;
vector<int> L(2 * 100002), R(2 * 100002);
struct DSU
{
    vector<int> par;
    int ncmp, mx;
    void inti(int n)
    {
        par.resize(n + 1, -1);
        for (int i = 1; i <= n; i++)
        {
            L[i] = i, R[i] = i;
        }
        ncmp = n;
        mx = 0;
    }
    int find(int u)
    {
        return par[u] < 0 ? u : par[u] = find(par[u]);
    }
    bool join(int b, int s)
    {
        b = find(b), s = find(s);
        if (b == s)
            return false;
        if (par[b] > par[s])
            swap(b, s);
        par[b] += par[s];
        par[s] = b;
        ncmp--;
        L[b] = min(L[b], L[s]);
        R[b] = max(R[b], R[s]);
        mx = max(mx, -1 * par[b]);
        return true;
    }
    int Max_size_cmp()
