        return mx;
    }
};
struct parity_DSU
{
    int par[N], dist[N], ncmp;
    void inti(int n)
    {
        memset(par, -1, sizeof par);
        fill(dist, dist + n, 0);
        ncmp = n;
    }
    // {root,dist_to_root}
    pair<int, int> find(int u)
    {
        if (par[u] < 0)
            return {u, 0};
        auto [root, dis] = find(par[u]);
        dist[u] ^= dist[par[u]];
        par[u] = root;
        return {root, dist[u]};
    }
    int addedge(int u, int v, int p)
    {
        auto [ru, du] = find(u);
        auto [rv, dv] = find(v);
        if (rv == ru)
            return (du ^ dv) ? 1 : -1;
        par[rv] = ru;
        dist[rv] = dv ^ du ^ p;
        return 0;
    }
};

int mod = 1e9 + 7;

int modSum(ll a, ll b)
{
    /// complexity: 1
    a = (a % mod + mod) % mod;
    b = (b % mod + mod) % mod;
    return (a + b) % mod;
}

int modProd(ll a, ll b)
{
    /// complexity: 1
    a = (a % mod + mod) % mod;
    b = (b % mod + mod) % mod;
    return (a * b) % mod;
}

int fastPow(int a, int b)
{
    /// complexity: log(b)
    if (b == 0)
        return 1;
    int temp = fastPow(a, b / 2);
    if (b % 2 == 0)
        return modProd(temp, temp);
    return modProd(modProd(a, temp), temp);
}
ll get(ll l, ll r)
{
    return 1LL * ((r - l + 1) * (((r - l + 1) - 1))) / 2;
}
