    DSU ds1;
    cin >> _t;
    while (_t--)
    {
        int n;
        cin >> n;
        vector<int> p(n + 1);
        DSU dsu;
        dsu.inti(n);
        for (int i = 1; i <= n; i++)
            cin >> p[i];
        vector<pair<int, int>> adj[n + 1];
        for (int i = 1; i <= n - 1; i++)
        {
            adj[abs(p[i] - p[i + 1])].push_back({i, i + 1});
        }
        vector<ll> ans;
        ll t = 0;
        for (int i = n - 1; i > 0; i--)
        {
            for (auto &it : adj[i])
            {
                if (dsu.find(it.first) == dsu.find(it.second))
                    continue;
                int x = it.first, y = it.second;
                t -= (get(L[dsu.find(x)], R[dsu.find(x)]) + get(L[dsu.find(y)], R[dsu.find(y)]));
                dsu.join(x, y);
                t += get(L[dsu.find(x)], R[dsu.find(y)]);
            }
            ans.push_back(t);
        }
        reverse(all(ans));
        for (int it : ans)
            cout << it << ' ';
        cout << '\n';
        for (int i = 1; i <= n; i++)
            adj[i].clear();
    }
    return 0;
}

