#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstring>
#include <string>
#include <queue>
#include <stack>
#include <deque>
#include <set>
#include <map>
#include <unordered_set>
#include <unordered_map>
#include <numeric>
#include <limits>
#include <iomanip>

using namespace std;

/* ===================== TYPES ===================== */
using ll = long long;
using pii = pair<int, int>;
using pll = pair<ll, ll>;
using vi = vector<int>;
using vll = vector<ll>;

/* ===================== MACROS ===================== */
#define pb push_back
#define ff first
#define ss second
#define all(x) (x).begin(), (x).end()
#define rall(x) (x).rbegin(), (x).rend()
#define sz(x) (int)(x).size()

/* ===================== I/O HELPERS ===================== */
template <typename T>
void read_vector(vector<T> &v)
{
    for (auto &x : v)
        cin >> x;
}

template <typename T>
void print_vector(const vector<T> &v, char sep = ' ')
{
    for (int i = 0; i < (int)v.size(); i++)
    {
        cout << v[i] << (i + 1 == (int)v.size() ? '\n' : sep);
    }
}

int main()
{
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    if (!(cin >> t)) return 0;
    while (t--)
    {
        int n;
        cin >> n;
        vll a(n);
        read_vector(a);

        vll arr;
        for (int i = 1; i < n; i++)
        {
            arr.pb(abs(a[i] - a[i - 1]));
        }

        vll last_small(n - 1);
        vll next_small(n - 1);
        vll ans(n - 1, 0);
        stack<pll> st;

        // 1. Find previous smaller (or equal) element
        for (int i = 0; i < n - 1; i++)
        {
            // Use >= here
            while (!st.empty() && st.top().ff >= arr[i])
            {
                st.pop();
            }
            last_small[i] = st.empty() ? -1 : st.top().ss;
            st.push({arr[i], i});
        }

        while(!st.empty()) st.pop();

        // 2. Find next strictly smaller element
        for (int i = n - 2; i >= 0; i--)
        {
            // Use > here to cleanly prevent duplicate counting
            while (!st.empty() && st.top().ff > arr[i])
            {
                st.pop();
            }
            next_small[i] = st.empty() ? n - 1 : st.top().ss;
            st.push({arr[i], i});
        }

        // 3. Count subarrays directly crossing index i
        for (int i = 0; i < n - 1; i++)
        {
            ll left_ways = i - last_small[i];
            ll right_ways = next_small[i] - i;

            ans[arr[i] - 1] += left_ways * right_ways;
        }
        ll s=0;
        for (int i=n-2;i>=0;i--){
            s+=ans[i];
            ans[i]=s;
        }

        print_vector(ans);
    }
    return 0;
}

